package springfox.documentation.builders;

import springfox.documentation.service.HttpAuthenticationScheme;
import springfox.documentation.service.VendorExtension;

import java.util.ArrayList;
import java.util.List;

import static springfox.documentation.builders.BuilderDefaults.*;

public class HttpAuthenticationBuilder {
  private String name;
  private String description;
  private String scheme;
  private String bearerFormat;
  private final List<VendorExtension> extensions = new ArrayList<>();

  public HttpAuthenticationBuilder name(String name) {
    this.name = name;
    return this;
  }

  public HttpAuthenticationBuilder scheme(String scheme) {
    this.scheme = scheme;
    return this;
  }

  public HttpAuthenticationBuilder bearerFormat(String bearerFormat) {
    this.bearerFormat = bearerFormat;
    return this;
  }

  public HttpAuthenticationBuilder description(String description) {
    this.description = description;
    return this;
  }

  public HttpAuthenticationBuilder extensions(List<VendorExtension> extensions) {
    this.extensions.addAll(nullToEmptyList(extensions));
    return this;
  }

  public HttpAuthenticationScheme build() {
    return new HttpAuthenticationScheme(
        name,
        description,
        "http",
        scheme,
        bearerFormat,
        extensions);
  }
}

package org.zalando.nakadi.plugin.auth;


import org.zalando.nakadi.plugin.api.authz.AuthorizationService;
import org.zalando.nakadi.plugin.api.authz.Resource;
import org.zalando.nakadi.plugin.api.authz.Subject;
import org.zalando.nakadi.plugin.api.exceptions.AuthorizationInvalidException;
import org.zalando.nakadi.plugin.api.exceptions.OperationOnResourceNotPermittedException;
import org.zalando.nakadi.plugin.api.exceptions.PluginException;

import javax.annotation.Nullable;
import java.util.List;
import java.util.Optional;

public class DefaultAuthorizationService implements AuthorizationService {

    @Override
    public boolean isAuthorized(final Operation operation, final Resource resource) throws PluginException {
        return true;
    }

    @Override
    public void isAuthorizationForResourceValid(final Resource resource) throws PluginException,
            AuthorizationInvalidException, OperationOnResourceNotPermittedException {
    }

    public DefaultAuthorizationService() {
        super();
    }

    @Override
    @Nullable
    public Optional<Subject> getSubject() {
        return Optional.empty();
    }

    @Override
    public List<Resource> filter(final List<Resource> input) throws PluginException {
        return input;
    }
}

package org.zalando.nakadi.repository.kafka;

import com.fasterxml.jackson.annotation.JsonProperty;

import java.util.Map;

public class BubukuSizeStats {
    public static class TotalStats {
        private final long usedKb;
        private final long freeKb;

        public TotalStats(
                @JsonProperty("used_kb") final long usedKb,
                @JsonProperty("free_kb") final long freeKb) {
            this.usedKb = usedKb;
            this.freeKb = freeKb;
        }

        public long getUsedKb() {
            return usedKb;
        }

        public long getFreeKb() {
            return freeKb;
        }
    }

    private final TotalStats totalStats;
    private final Map<String, Map<String, Long>> perPartitionStats;

    public BubukuSizeStats(
            @JsonProperty("disk") final TotalStats totalStats,
            @JsonProperty("topics") final Map<String, Map<String, Long>> perPartitionStats) {
        this.totalStats = totalStats;
        this.perPartitionStats = perPartitionStats;
    }

    public TotalStats getTotalStats() {
        return totalStats;
    }

    public Map<String, Map<String, Long>> getPerPartitionStats() {
        return perPartitionStats;
    }
}
